() => {
  window.__fbqLog = [];
  try {
    if (window.fbq && !window.__fbqWrapped) {
      const orig = window.fbq;
      const wrapped = function(){ try{window.__fbqLog.push(Array.prototype.slice.call(arguments).map(x=>typeof x==='object'?JSON.stringify(x):String(x)));}catch(e){} return orig.apply(this, arguments); };
      for (const k in orig){ try{ wrapped[k]=orig[k]; }catch(e){} }
      wrapped.callMethod=orig.callMethod; wrapped.queue=orig.queue; wrapped.loaded=orig.loaded; wrapped.version=orig.version;
      window.fbq=wrapped; window._fbq=wrapped; window.__fbqWrapped=true;
    }
  } catch(e){}
  const tr = (performance.getEntriesByType('resource')||[]).map(e=>e.name).filter(n=>/facebook\.com\/tr/.test(n)).map(n=>{const m=n.match(/[?&]ev=([^&]+)/);return m?decodeURIComponent(m[1]):'(none)';});
  return { armed: !!window.__fbqWrapped, hasFbq: typeof window.fbq==='function', trEventsBeforeAdd: tr };
}

() => {
  const sels=['product-form button[name=\"add\"]','button[name=\"add\"]','.product-form__submit','form[action*=\"/cart/add\"] [type=\"submit\"]','button[type=\"submit\"][name=\"add\"]'];
  let btn=null,used=null;
  for(const s of sels){ const e=document.querySelector(s); if(e){btn=e;used=s;break;} }
  if(!btn) return {clicked:false, reason:'no add button found'};
  const disabled = !!btn.disabled;
  let err=null;
  try{ btn.click(); }catch(e){ err=String(e); }
  return {clicked:true, selector:used, disabled, btnText:(btn.textContent||'').trim().slice(0,40), err};
}

